    def convert_base(n, b):
        if n == 0:
            return '0'
        digits = []
        while n:
            digits.append(int(n % b))
            n //= b
        return ''.join(map(str, digits[::-1]))

    base7 = convert_base(629, 7)
    base8 = convert_base(629, 8)
    common_digits = set(base7) & set(base8)
    try:
        return int(str(answer).strip()) == len(common_digits)
    except Exception:
